<?php
declare(strict_types=1);require_once __DIR__.'/_layout.php';$pdo=obtenerConexion();$id=docenteId($_GET['id']??0);$docenteId=docenteSupervisadoAtenea($pdo);$GLOBALS['docentePortalId']=$docenteId;exigirCursoDocente($pdo,$docenteId,$id);$q=$pdo->prepare('SELECT * FROM asignaturas WHERE id=:id');$q->execute(['id'=>$id]);$curso=$q->fetch();$q=$pdo->prepare("SELECT COUNT(*) FROM estudiantes_docentes WHERE docente_id=:d AND asignatura_id=:a AND estado='activo'");$q->execute(['d'=>$docenteId,'a'=>$id]);$estudiantes=(int)$q->fetchColumn();$q=$pdo->prepare('SELECT id,titulo,estado,created_at FROM contenidos WHERE docente_id=:d AND asignatura_id=:a ORDER BY created_at DESC LIMIT 10');$q->execute(['d'=>$docenteId,'a'=>$id]);$contenidos=$q->fetchAll();$q=$pdo->prepare('SELECT id,titulo,estado,fecha_cierre FROM evaluaciones WHERE docente_id=:d AND asignatura_id=:a ORDER BY created_at DESC LIMIT 10');$q->execute(['d'=>$docenteId,'a'=>$id]);$evaluaciones=$q->fetchAll();docenteCabecera($curso['nombre'],'cursos','Detalle real del curso asignado.');?>
<div class="row"><div class="col-lg-8"><div class="card card-rounded"><div class="card-body"><span class="badge badge-primary"><?=atenea_e($curso['codigo'])?></span><p class="mt-3"><?=atenea_e((string)$curso['descripcion'])?></p><h2 class="h5 mt-4">Contenidos recientes</h2><?php foreach($contenidos as$c):?><p><a href="<?=docenteUrl('contenidos.php',['curso'=>$id])?>"><?=atenea_e($c['titulo'])?></a><span class="badge bg-light text-dark float-end"><?=atenea_e($c['estado'])?></span></p><?php endforeach;?><?php if(!$contenidos):?><p class="text-muted">No hay contenidos registrados.</p><?php endif;?><h2 class="h5 mt-4">Evaluaciones</h2><?php foreach($evaluaciones as$e):?><p><a href="<?=docenteUrl('evaluaciones.php',['curso'=>$id])?>"><?=atenea_e($e['titulo'])?></a><span class="badge bg-light text-dark float-end"><?=atenea_e($e['estado'])?></span></p><?php endforeach;?><?php if(!$evaluaciones):?><p class="text-muted">No hay evaluaciones registradas.</p><?php endif;?></div></div></div><div class="col-lg-4"><div class="card card-rounded"><div class="card-body"><h2 class="h5">Resumen</h2><p><strong><?=$estudiantes?></strong> estudiantes activos</p><a class="btn btn-outline-primary w-100 mb-2" href="<?=docenteUrl('estudiantes.php',['curso'=>$id])?>">Ver estudiantes</a><a class="btn btn-outline-primary w-100 mb-2" href="<?=docenteUrl('contenidos.php',['curso'=>$id])?>">Gestionar contenidos</a><a class="btn btn-outline-primary w-100" href="<?=docenteUrl('evaluaciones.php',['curso'=>$id])?>">Gestionar evaluaciones</a></div></div></div></div><?php docentePie();
